#include <bits/stdc++.h>
#define int long long
using namespace std;
const int MOD = 10007;
int n , m;
int num[ 100005 ];
int col[ 100005 ];
int ans;
signed main() {
	cin >> n >> m;
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> num[ i ];
	}
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> col[ i ];
	}
	vector < vector < int > > cnt( m + 1 , vector < int > ( 2 , 0 ) );
	vector < vector < int > > sumA( m + 1 , vector < int > ( 2 , 0 ) );
	vector < vector < int > > sumB( m + 1 , vector < int > ( 2 , 0 ) );
	vector < vector < int > > sumC( m + 1 , vector < int > ( 2 , 0 ) );
	for( int i = 1 ; i <= n ; i++ ) {
		int c = col[ i ];
		int p = i % 2;
		cnt[ c ][ p ]++;
		sumA[ c ][ p ] = ( sumA[ c ][ p ] + i ) % MOD;
		sumB[ c ][ p ] = ( sumB[ c ][ p ] + num[ i ] ) % MOD;
		sumC[ c ][ p ] = ( sumC[ c ][ p ] + i * num[ i ] ) % MOD;
	}
	for( int c = 1 ; c <= m ; c++ ) {
		for( int p = 0 ; p < 2 ; p++ ) {
			int k = cnt[ c ][ p ];
			if( k >= 2 ) {
				int A = sumA[ c ][ p ];
				int B = sumB[ c ][ p ];
				int C = sumC[ c ][ p ];
				int add = ( ( k - 2 ) % MOD * C % MOD + A * B % MOD ) % MOD;
				ans = ( ans + add ) % MOD;
			}
		}	
	}
	cout << ans;
	return 0;
}
